<script setup>import {storeToRefs} from 'pinia';import {useEnrollmentStore} from '../stores/enrollment';const store=useEnrollmentStore();const {enrolledCourses,totalCredits}=storeToRefs(store);</script><template><main><h1>My profile</h1><p>Total enrolled credits: {{totalCredits}}</p><ul><li v-for="course in enrolledCourses" :key="course.id">{{course.name}} <button @click="store.unenroll(course.id)">Remove</button></li></ul><p v-if="!enrolledCourses.length">No courses enrolled.</p><button v-if="enrolledCourses.length" @click="store.$reset()">Clear enrollment</button></main></template>
